content:
ata_dir, config.embedding.dimensions)?);
            Ok((store.clone() as Arc<dyn traits::QueryableStore>, store as Arc<dyn traits::GraphStore>))
        }
        StoreType::Postgres => {
            create_store_with_graph(config).await
